[
  {
    "text": "Fragility of Gemini Deep Research's extended reasoning chains is operationally defined as a >20% rate of logical inconsistency (contradiction or non-sequitur) in output across a benchmark of 100 multi-step reasoning tasks with chain length >15.",
    "topic": "Fragility definition"
  },
  {
    "text": "A physics-grounded self-verification module is concretely specified as a post-hoc check that each intermediate reasoning step does not violate conservation laws, frame invariance, or known physical constants for the domain.",
    "topic": "Self-verification specification"
  },
  {
    "text": "An A/B test of Gemini Deep Research with and without the physics-grounded self-verification module, measuring fragility as defined, would establish whether the two claims (fragility and lack of self-verification) are causally related: a significant reduction in fragility would show the lack caused it; no reduction would show fragility has other sources.",
    "topic": "Contradiction resolution procedure"
  },
  {
    "text": "Existing Gemini Deep Research chain traces can be analyzed post hoc for violation of conservation laws as a proxy for missing self-verification, providing preliminary evidence of whether fragility correlates with such violations.",
    "topic": "Retrospective test feasibility"
  }
]
